import React, { useState } from 'react';
import { useSelector } from 'react-redux';
import { motion, AnimatePresence } from 'framer-motion';
import { Link } from 'react-router-dom';
import Navbar from '../components/Common/Navbar';
import './Leaderboard.css';

const MOCK_DATA = [
  { rank: 1,  username: 'SignMaster',    xp: 15420, streak: 45, lessons: 89, accuracy: 96 },
  { rank: 2,  username: 'ISLPro',        xp: 14850, streak: 38, lessons: 76, accuracy: 94 },
  { rank: 3,  username: 'HandTalker',    xp: 13200, streak: 30, lessons: 68, accuracy: 91 },
  { rank: 4,  username: 'SignLearner',   xp: 11500, streak: 25, lessons: 55, accuracy: 89 },
  { rank: 5,  username: 'GestureGuru',   xp: 10800, streak: 22, lessons: 52, accuracy: 88 },
  { rank: 6,  username: 'QuietSpeaker',  xp: 9500,  streak: 18, lessons: 45, accuracy: 85 },
  { rank: 7,  username: 'SignNewbie',    xp: 8200,  streak: 15, lessons: 38, accuracy: 82 },
  { rank: 8,  username: 'LearningSigns', xp: 7400,  streak: 12, lessons: 32, accuracy: 80 },
  { rank: 9,  username: 'ISLFan',        xp: 6800,  streak: 10, lessons: 28, accuracy: 78 },
  { rank: 10, username: 'NewLearner',    xp: 5500,  streak: 7,  lessons: 22, accuracy: 75 },
];

const TIMEFRAMES = ['Daily', 'Weekly', 'Monthly', 'All Time'];
const CATEGORIES = [
  { id: 'xp',       label: 'XP',       getValue: (u) => `${u.xp.toLocaleString()} XP` },
  { id: 'streak',   label: 'Streak',   getValue: (u) => `${u.streak} days` },
  { id: 'lessons',  label: 'Lessons',  getValue: (u) => `${u.lessons} lessons` },
  { id: 'accuracy', label: 'Accuracy', getValue: (u) => `${u.accuracy}%` },
];

const AVATAR_COLORS = [
  'linear-gradient(135deg, #A855F7, #7C3AED)',
  'linear-gradient(135deg, #EC4899, #BE185D)',
  'linear-gradient(135deg, #10B981, #059669)',
  'linear-gradient(135deg, #F59E0B, #D97706)',
  'linear-gradient(135deg, #3B82F6, #1D4ED8)',
  'linear-gradient(135deg, #EF4444, #B91C1C)',
];

const RANK_STYLES = {
  1: { bg: 'linear-gradient(135deg, #FEF3C7, #FDE68A)', border: '#F59E0B', text: '#92400E', badge: '#F59E0B' },
  2: { bg: 'linear-gradient(135deg, #F1F5F9, #E2E8F0)', border: '#94A3B8', text: '#475569', badge: '#94A3B8' },
  3: { bg: 'linear-gradient(135deg, #FEF0E7, #FDE8D0)', border: '#F97316', text: '#7C2D12', badge: '#F97316' },
};

const Leaderboard = () => {
  const { user } = useSelector(state => state.auth);
  const [timeframe, setTimeframe] = useState('Weekly');
  const [category, setCategory] = useState('xp');

  const activeCat = CATEGORIES.find(c => c.id === category);

  const currentUser = {
    rank: 24,
    username: user?.username || 'You',
    xp: user?.xp_points || 2500,
    streak: user?.streak_days || 15,
    lessons: 24,
    accuracy: 85,
  };

  return (
    <div className="lb-page">
      {/* Background */}
      <div className="lb-bg">
        <div className="lb-bg-main" />
        <div className="lb-bg-c1" />
        <div className="lb-bg-c2" />
        <div className="lb-bg-pattern" />
      </div>

      <Navbar />

      <main className="lb-main">
        {/* Header */}
        <motion.div
          className="lb-header"
          initial={{ opacity: 0, y: -20 }}
          animate={{ opacity: 1, y: 0 }}
        >
          <div>
            <h1 className="lb-title">Leaderboard</h1>
            <p className="lb-subtitle">See how you rank among ISL learners worldwide</p>
          </div>
          <Link to="/practice" className="lb-cta-btn">Practice to Climb</Link>
        </motion.div>

        {/* Filters */}
        <motion.div
          className="lb-filters"
          initial={{ opacity: 0, y: 10 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.1 }}
        >
          <div className="filter-row">
            <span className="filter-label">Timeframe</span>
            <div className="filter-tabs">
              {TIMEFRAMES.map(t => (
                <button
                  key={t}
                  className={`filter-tab ${timeframe === t ? 'active' : ''}`}
                  onClick={() => setTimeframe(t)}
                >
                  {t}
                </button>
              ))}
            </div>
          </div>
          <div className="filter-row">
            <span className="filter-label">Rank by</span>
            <div className="filter-tabs">
              {CATEGORIES.map(c => (
                <button
                  key={c.id}
                  className={`filter-tab ${category === c.id ? 'active' : ''}`}
                  onClick={() => setCategory(c.id)}
                >
                  {c.label}
                </button>
              ))}
            </div>
          </div>
        </motion.div>

        {/* Podium */}
        <motion.div
          className="podium"
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.2 }}
        >
          {/* 2nd */}
          <div className="podium-item podium-2">
            <div className="podium-avatar" style={{ background: AVATAR_COLORS[1] }}>
              {MOCK_DATA[1].username.charAt(0)}
            </div>
            <div className="podium-rank-badge silver">2</div>
            <div className="podium-name">{MOCK_DATA[1].username}</div>
            <div className="podium-value">{activeCat.getValue(MOCK_DATA[1])}</div>
            <div className="podium-bar podium-bar-2" />
          </div>

          {/* 1st */}
          <div className="podium-item podium-1">
            <div className="podium-crown">&#9813;</div>
            <div className="podium-avatar podium-avatar-1" style={{ background: AVATAR_COLORS[0] }}>
              {MOCK_DATA[0].username.charAt(0)}
            </div>
            <div className="podium-rank-badge gold">1</div>
            <div className="podium-name">{MOCK_DATA[0].username}</div>
            <div className="podium-value">{activeCat.getValue(MOCK_DATA[0])}</div>
            <div className="podium-bar podium-bar-1" />
          </div>

          {/* 3rd */}
          <div className="podium-item podium-3">
            <div className="podium-avatar" style={{ background: AVATAR_COLORS[2] }}>
              {MOCK_DATA[2].username.charAt(0)}
            </div>
            <div className="podium-rank-badge bronze">3</div>
            <div className="podium-name">{MOCK_DATA[2].username}</div>
            <div className="podium-value">{activeCat.getValue(MOCK_DATA[2])}</div>
            <div className="podium-bar podium-bar-3" />
          </div>
        </motion.div>

        {/* Table */}
        <motion.div
          className="lb-table-card"
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.3 }}
        >
          <div className="lb-table-header">
            <span className="th-rank">Rank</span>
            <span className="th-user">User</span>
            <span className="th-value">{activeCat.label}</span>
            <span className="th-streak">Streak</span>
          </div>

          <div className="lb-table-body">
            {MOCK_DATA.slice(3).map((user, i) => (
              <motion.div
                key={user.rank}
                className="lb-row"
                initial={{ opacity: 0, x: -10 }}
                animate={{ opacity: 1, x: 0 }}
                transition={{ delay: 0.35 + i * 0.05 }}
                whileHover={{ x: 4, background: 'rgba(168,85,247,0.04)' }}
              >
                <span className="td-rank">{user.rank}</span>
                <div className="td-user">
                  <div className="lb-avatar" style={{ background: AVATAR_COLORS[i % AVATAR_COLORS.length] }}>
                    {user.username.charAt(0)}
                  </div>
                  <span className="lb-username">{user.username}</span>
                </div>
                <span className="td-value">{activeCat.getValue(user)}</span>
                <span className="td-streak">{user.streak}d</span>
              </motion.div>
            ))}
          </div>
        </motion.div>

        {/* Your Rank */}
        <motion.div
          className="your-rank-card"
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.5 }}
        >
          <div className="your-rank-left">
            <span className="your-rank-label">Your Rank</span>
            <span className="your-rank-num">#{currentUser.rank}</span>
            <span className="your-rank-sub">out of 1,245 learners</span>
          </div>
          <div className="your-rank-stats">
            <div className="yr-stat">
              <span className="yr-val purple">{currentUser.xp.toLocaleString()}</span>
              <span className="yr-lbl">XP</span>
            </div>
            <div className="yr-stat">
              <span className="yr-val">{currentUser.streak}</span>
              <span className="yr-lbl">Streak</span>
            </div>
            <div className="yr-stat">
              <span className="yr-val green">{currentUser.accuracy}%</span>
              <span className="yr-lbl">Accuracy</span>
            </div>
          </div>
          <Link to="/practice" className="yr-cta">Keep Practicing</Link>
        </motion.div>
      </main>
    </div>
  );
};

export default Leaderboard;
